import{_ as t,c as a,o as n,al as i}from"./chunks/framework.DM883ANZ.js";const g=JSON.parse('{"title":"Installing MAVLink Toolchain","description":"Installing MAVLink Toolchain — MAVLink message, enum and command reference.","frontmatter":{"head":[["meta",{"property":"og:title","content":"Installing MAVLink Toolchain"}],["meta",{"property":"og:description","content":"Installing MAVLink Toolchain — MAVLink message, enum and command reference."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://mavlink.io/en/getting_started/installation.html"}],["link",{"rel":"canonical","href":"https://mavlink.io/en/getting_started/installation.html"}]]},"headers":[],"relativePath":"en/getting_started/installation.md","filePath":"en/getting_started/installation.md","lastUpdated":1782885791000}'),l={name:"en/getting_started/installation.md"};function s(o,e,r,p,h,c){return n(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="installing-mavlink-toolchain" tabindex="-1">Installing MAVLink Toolchain <a class="header-anchor" href="#installing-mavlink-toolchain" aria-label="Permalink to &quot;Installing MAVLink Toolchain&quot;">​</a></h1><p>This topic explains how to install the <a href="https://github.com/mavlink/mavlink" target="_blank" rel="noreferrer">MAVLink toolchain</a>. The toolchain includes the <a href="./../messages/">XML message definitions</a> as well as the GUI/command line tools that use the definitions to <a href="./../getting_started/generate_libraries.html">Generate MAVLink Source Files</a>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You do not need to install or generate the source files if you are using the C programming language and a standard <a href="./../messages/#dialects">dialect</a>. Just get the <a href="./../#prebuilt_libraries">prebuilt libraries</a> and then jump to <a href="./../mavgen_c/">Using C Libraries</a>.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>The requirements for using the <em>MAVLink generator</em> are:</p><ul><li>Python 3</li><li>Python 3 Pip</li><li><a href="https://wiki.python.org/moin/TkInter" target="_blank" rel="noreferrer">TkInter</a> (required to use the GUI tool), included as of Python 3.7.</li></ul><p>If you are creating new XML definitions you should also install lxml and libxml2 for XML validation and formatting.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>To install the MAVLink toolchain:</p><ol><li><p>Install Python 3.7+:</p><ul><li><p><strong>Windows:</strong> Download from <a href="https://www.python.org/downloads/" target="_blank" rel="noreferrer">Python for Windows</a></p></li><li><p><strong>Ubuntu Linux</strong> Make sure Python and Pip are both installed:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt install python3 python3-pip</span></span></code></pre></div></li></ul></li><li><p>Clone the official <a href="https://github.com/mavlink/mavlink" target="_blank" rel="noreferrer">mavlink repo</a> or your fork with your custom dialect:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/mavlink/mavlink.git --recursive</span></span>
<span class="line"><span>cd mavlink</span></span></code></pre></div></li><li><p>Install the required packages:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python3 -m pip install -r pymavlink/requirements.txt</span></span></code></pre></div></li></ol><p>Now you are ready to <a href="./../getting_started/generate_libraries.html">Generate MAVLink Libraries</a>.</p>`,11)])])}const u=t(l,[["render",s]]);export{g as __pageData,u as default};
